sql:
SELECT status, COUNT(*) AS dataset_count
FROM genetic_datasets
GROUP BY status;

SELECT dataset_name, version
FROM genetic_datasets
WHERE dataset_id = 0;

SELECT COUNT(*) 
FROM genetic_datasets 
WHERE uploaded_by = 1 AND status = 'active';

SELECT users.user_name
FROM users
JOIN genetic_datasets ON users.user_id = genetic_datasets.uploaded_by;

SELECT gene_symbol, chromosome
FROM gene_annotations
WHERE gene_length > (
    SELECT AVG(gene_length)
    FROM gene_annotations
);

SELECT dataset_name, source
FROM genetic_datasets
ORDER BY upload_date ASC;
